INSERT INTO `cake` VALUES ('기념일케이크',1,'계란판 케이크','귀여운 병아리가 계란판 안에 들어있는 케이크입니다.',30000,6,'anniversarycake(1).jpg'),('기념일케이크',2,'취업 축하 케이크','취업 축하 메시지를 전하기 좋은 양복 케이크입니다.',30000,6,'anniversarycake(2).jpg'),('기념일케이크',3,'할 말이 너무 많은 케이크','할 말은 너무 많은데 케이크가 너무 작네 일단 태어나줘서 고맙구 * 이름 제외 문구 수정 불가',28000,6,'anniversarycake(3).jpg'),('기념일케이크',4,'할 일 리스트 케이크','할 일 리스트를 적을 수 있는 케이크입니다. * 요청사항에 한글 10자 이내, 영문 15자 이내로 작성해 주시면 요청사항 대로 글씨 적어드립니다. 미작성 시 공백으로 제작됩니다.',30000,5,'anniversarycake(4).jpg'),('기념일케이크',5,'폴라로이드 사진 케이크','꽃밭에 폴라로이드 카메라로 찍은 사진을 올려놓은 것 같은 케이크입니다. * 그림 변경 불가. 요청사항에 한글 6자 이내, 영문 8자 이내로 작성해 주시면 요청사항 대로 글씨 적어드립니다. 미작성 시 공백으로 제작됩니다.',35000,5,'anniversarycake(5).jpg'),('기념일케이크',6,'분홍꽃 카드 케이크','분홍색 꽃에 둘러싸인 카드 안에 축하 메시지를 써드립니다. * 요청사항에 한글 8자 이내, 영문 13자 이내로 작성해 주시면 요청사항 대로 글씨 적어드립니다. 미작성 시 공백으로 제작됩니다.',35000,5,'anniversarycake(6).jpg'),('기념일케이크',7,'비행기 케이크','하늘 위를 날아가는 비행기 케이크입니다.',27000,5,'anniversarycake(7).jpg'),('기념일케이크',8,'카네이션 케이크','카네이션 케이크로 감사의 마음을 전해보세요.',27000,5,'anniversarycake(8).jpg'),('기념일케이크',9,'나비와 장미케이크','나비와 장미로 장식된 하트 모양 케이크입니다.',33000,9,'anniversarycake(9).jpg'),('기념일케이크',10,'곰두마리 레터링 케이크','* 요청사항에 한글 10자 이내, 영문 15자 이내로 작성해 주시면 요청사항 대로 글씨 적어드립니다. 미작성 시 공백으로 제작됩니다.',26000,5,'anniversarycake(10).jpg'),('기념일케이크',11,'딸기 모자 곰돌이 케이크','딸기를 모자처럼 쓰고 있는 귀여운 곰돌이 케이크입니다.',31000,5,'anniversarycake(11).jpg'),('기념일케이크',12,'항공사 케이크','요청사항에 항공사 알려주시면 항공사 비행기로 제작해드립니다.',31000,5,'anniversarycake(12).jpg'),('기념일케이크',13,'루피 화환 케이크','화환 케이크입니다. * 개업 축하, 결혼 축하 등 요청사항에 한글 4글자 단어로 입력하시면 요청사항 대로 글씨 적어드립니다. 미작성 시 공백으로 제작됩니다.',30000,6,'anniversarycake(13).jpg'),('기념일케이크',14,'날 데리고 살아줘요 케이크','귀엽게 얘기하기 좋은 케이크입니다. * 문구 수정 불가',26000,5,'anniversarycake(14).jpg'),('기념일케이크',15,'100일 케이크','100일, 200일, 1주년 등에 좋은 케이크입니다. * 요청사항에 한글 4글자 이내로 써주시면 요청사항 대로 글씨 적어드립니다. 미작성 시 공백으로 제작됩니다.',26000,5,'anniversarycake(15).jpg'),('기념일케이크',16,'딸기 모자 강아지 케이크','딸기를 모자처럼 쓰고 있는 강아지 두 마리가 있는 케이크입니다. * 요청사항에 한글 10자 이내, 영문 15자 이내로 작성해 주시면 요청사항 대로 글씨 적어드립니다. 미작성 시 공백으로 제작됩니다.',30000,5,'anniversarycake(16).jpg'),('기념일케이크',17,'아가 건강하게 만나자 케이크','* 요청사항에 아기 이름 작성해 주시면 요청사항 대로 글씨 적어드립니다. 미작성 시 \"아가\"로 제작됩니다.',29000,5,'anniversarycake(17).jpg'),('기념일케이크',18,'경찰 승진 케이크','경찰 마크가 그려진 케이크입니다. \"축승진\" 또는 \"축합격\" 선택 가능합니다. * 미선택 시 공란으로 제작됩니다.',35000,5,'anniversarycake(18).jpg'),('기념일케이크',19,'날짜 지정 디데이 케이크','디데이 또는 기념일을 나타내보세요! * 상단 숫자와 하단 날짜만 지정 가능합니다. 미작성 시 공백으로 제작됩니다.',26000,5,'anniversarycake(19).jpg'),('기념일케이크',20,'크리스마스 딸기 케이크','메리크리스마스! 딸기 케이크입니다. 빵 시트 사이에 딸기가 들어있습니다. * 문구 수정 불가',27000,5,'anniversarycake(20).jpg'),('생일케이크',21,'소두 병아리 케이크','머리가 아주 작은 병아리 케이크입니다.* 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',30000,6,'birthcake(1).jpg'),('생일케이크',22,'초록 하트 케이크','하얀 초코 구슬이 박혀있는 초록색 하트 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',28000,5,'birthcake(2).jpg'),('생일케이크',23,'핑크 리본 케이크','쨍한 핑크색 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',27000,15,'birthcake(3).jpg'),('생일케이크',24,'키티 케이크','키티 3명이 있는 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',28000,5,'birthcake(4).jpg'),('생일케이크',25,'커비 케이크','꼬깔모자를 쓴 커비 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',33000,6,'birthcake(5).jpg'),('생일케이크',26,'사각 리본 케이크','사각형 모양의 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',29000,5,'birthcake(6).jpg'),('생일케이크',27,'밤하늘 케이크','밤하늘이 반짝이는 듯한 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',33000,5,'birthcake(7).jpg'),('생일케이크',28,'사각 생일 케이크','사각형에 심플하게 레터링이 있는 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',27000,5,'birthcake(8).jpg'),('생일케이크',29,'소두 돼지 케이크','머리가 아주 작은 돼지 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',31000,5,'birthcake(9).jpg'),('생일케이크',30,'소두 곰돌이 케이크','머리가 아주 작은 곰돌이 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',31000,5,'birthcake(10).jpg'),('생일케이크',31,'미니 사각 생일 케이크','1호보다 작은 미니 사이즈입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',22000,6,'birthcake(11).jpg'),('생일케이크',32,'너의 편이 되어줄게 케이크','귀여운 캐릭터가 그려져있는 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',29000,5,'birthcake(12).jpg'),('생일케이크',33,'짱구 케이크','짱구 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',34000,5,'birthcake(13).jpg'),('생일케이크',34,'기영이 케이크','기영이가 바나나를 먹는 모습의 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',30000,5,'birthcake(14).jpg'),('생일케이크',35,'인물과 꽃 케이크','*문구는 요청사항에 한글 10자, 영문 15자 이내로 작성해주세요. 미작성 시 공백으로 제작. 장발, 단발 원하시는 머리길이를 요청사항에 써주세요. 미작성 시 머리 짧은 인물로 제작됩니다.',35000,5,'birthcake(15).jpg'),('생일케이크',36,'부모님 생신 축하 케이크','* 요청사항에서 어머니, 아버지 중에 선택해 주세요. 미작성 시 상품 이미지와 똑같이 제작됩니다.',33000,5,'birthcake(16).jpg'),('생일케이크',37,'오늘은 무슨 날 케이크','* 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',26000,5,'birthcake(17).jpg'),('생일케이크',38,'반려동물과 함께 케이크','귀여운 반려동물과 인간이 그려진 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',26000,5,'birthcake(18).jpg'),('생일케이크',39,'달력 케이크','달력 처럼 날짜에 동그라미 표시가 되어있는 케이크입니다. * 날짜 제외하고는 수정 불가합니다. 표시할 날짜를 요청사항에 써주세요. 미작성 시 표시 제외하고 제작됩니다.',30000,5,'birthcake(19).jpg'),('생일케이크',40,'대두 곰돌이 케이크','머리가 큰 곰돌이 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',31000,5,'birthcake(20).jpg'),('결혼식케이크',41,'품절 케이크','품절 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',27000,5,'weddingcake(1).jpg'),('결혼식케이크',42,'꽃길 축하 케이크','결혼 축하 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',32000,6,'weddingcake(2).jpg'),('결혼식케이크',43,'흰색 하트 케이크','흰색 하트 모양 생크림 케이크입니다. * 문구 없음',30000,5,'weddingcake(3).jpg'),('결혼식케이크',44,'2단 흰색 리본 케이크','2단 케이크입니다. 리본 장식이 붙어있습니다. 제거 후 섭취하세요. * 문구 없음',45000,5,'weddingcake(4).jpg'),('결혼식케이크',45,'2단 골드 초코볼 케이크','골드 색상의 초코볼이 장식되어 있는 2단 케이크입니다. * 문구 없음',45000,5,'weddingcake(5).jpg'),('결혼식케이크',46,'빈티지 꽃 케이크','빈티지 한 느낌을 살린 꽃 장식 케이크입니다. * 문구 없음',32000,5,'weddingcake(6).jpg'),('결혼식케이크',47,'빈티지 골드 초코볼 케이크','빈티지 한 느낌을 살린 꽃 장식에 골드 초코볼이 장식된 케이크입니다. * 문구 없음',33000,5,'weddingcake(7).jpg'),('결혼식케이크',48,'안개꽃 케이크 골드','안개꽃이 장식 되어 있는 케이크입니다. 안개꽃 제거 후 섭취하세요. 골드 색상의 초코볼이 장식되어 있습니다. * 배송 중 안개꽃이 일부 케이크에 떨어질 수 있습니다. 해당 사항으로 교환/환불 불가.',33000,6,'weddingcake(8).jpg'),('결혼식케이크',49,'큰 리본 장식 케이크','큰 리본이 케이크 옆면에 장식되어 있습니다. * 문구 없음',33000,5,'weddingcake(9).jpg'),('결혼식케이크',50,'안개꽃 케이크 실버','안개꽃이 장식 되어 있는 케이크입니다. 안개꽃 제거 후 섭취하세요. 실버 색상의 초코볼이 장식되어 있습니다. * 배송 중 안개꽃이 일부 케이크에 떨어질 수 있습니다. 해당 사항으로 교환/환불 불가.',33000,5,'weddingcake(10).jpg'),('결혼식케이크',51,'사각 체리 케이크','사각형 모양의 케이크입니다. 체리가 올라가있습니다. * 문구 없음',30000,5,'weddingcake(11).jpg'),('결혼식케이크',52,'반지 프로포즈 케이크','반지 그림이 그려진 프로포즈용 케이크입니다. * 이름 제외하고는 수정 불가합니다. 이름은 요청사항에 써주세요. 미작성 시 이름 제외하고 제작됩니다.',27000,5,'weddingcake(12).jpg'),('결혼식케이크',53,'웨딩데이 케이크','결혼 날짜가 적힌 케이크입니다. * 날짜 제외하고는 수정 불가합니다. 날짜는 요청사항에 써주세요. 미작성 시 날짜 제외하고 제작됩니다.',27000,5,'weddingcake(13).jpg'),('결혼식케이크',54,'웨딩 포켓 케이크','*문구는 요청사항에 한글 10자, 영문 15자 이내로 작성해주세요. 미작성 시 공백으로 제작됩니다.',30000,5,'weddingcake(14).jpg'),('결혼식케이크',55,'신혼부부 케이크','귀여운 신혼부부가 올라간 케이크입니다. * 문구 수정 불가',36000,5,'weddingcake(15).jpg'),('결혼식케이크',56,'왕관 케이크','왕관 장식이 올라간 케이크입니다. 왕관 제거 후 섭취해주세요. * 문구 없음',33000,5,'weddingcake(16).jpg'),('결혼식케이크',57,'품절 초 케이크','SOLD OUT 문자 초가 함께 배송됩니다. 흰색 리본이 장식되어 있습니다. 제거 후 섭취하세요. * 문구 없음',33000,5,'weddingcake(17).jpg'),('결혼식케이크',58,'미니 신혼부부 케이크','손바닥보다 작은 완전 미니 케이크입니다!! *문구는 요청사항에 한글 10자, 영문 15자 이내로 작성해주세요. 미작성 시 공백으로 제작됩니다.',15000,11,'weddingcake(18).jpg'),('결혼식케이크',59,'웨딩드레스 케이크','웨딩드레스 모양의 케이크입니다. * 문구 없음',40000,6,'weddingcake(19).jpg'),('결혼식케이크',60,'사각 품절 케이크','사각형 모양의 케이크입니다. * 문구 수정 불가',30000,7,'weddingcake(20).jpg'),(NULL,61,'도안 케이크',NULL,0,1,''),(NULL,62,'디자인 케이크',NULL,22000,1,''),(NULL,63,'디자인 케이크',NULL,22000,1,''),(NULL,64,'도안 케이크',NULL,0,1,''),(NULL,65,'도안 케이크',NULL,0,1,''),(NULL,66,'디자인 케이크',NULL,22000,1,''),(NULL,67,'디자인 케이크',NULL,22000,0,''),(NULL,68,'디자인 케이크',NULL,22000,0,''),(NULL,69,'디자인 케이크',NULL,22000,0,''),(NULL,70,'디자인 케이크',NULL,22000,0,''),(NULL,71,'디자인 케이크',NULL,22000,0,''),(NULL,72,'디자인 케이크',NULL,22000,0,''),(NULL,73,'도안 케이크',NULL,0,0,''),(NULL,74,'디자인 케이크',NULL,22000,0,''),(NULL,75,'디자인 케이크',NULL,22000,0,''),(NULL,76,'디자인 케이크',NULL,22000,0