--
-- Table structure for table `cart`
--

DROP TABLE IF EXISTS `cart`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `cart` (
  `ctNo` char(40) NOT NULL,
  `prdNo` int NOT NULL,
  `ctQty` int DEFAULT NULL,
  `memId` varchar(50) CHARACTER SET euckr COLLATE euckr_korean_ci DEFAULT NULL,
  `memNickname` char(20) DEFAULT NULL,
  `prdCakesize` char(50) DEFAULT NULL,
  `prdTaste` char(50) DEFAULT NULL,
  `prdFruit` char(50) DEFAULT NULL,
  `prdTopcream` char(50) DEFAULT NULL,
