INSERT INTO `question` VALUES (3,NULL,'졸업하자','제가 그림을 못 그려서 직접 도안을 그리지는 못하겠는데 이 캐릭터로 도안 할 수 있나요? 이 장면 그려주세요 케이크에...!! 저 그림 그대로 도안으로 하고 싶어요. 저렇게 하면 얼마인가요?','도안문의','uploads/다운로드 (1).jpg','2025-04-08 18:10:15',1,'1111',NULL,NULL,NULL,'이 캐릭터 그려주실 수 있나요???'),(4,NULL,'링바링','주문할 때 배송 일자 4월 4일로 선택했어요. 근데 일정이 바뀌어서 4월 7일로 바꾸고 싶은데 가능한가요?ㅠㅠㅠ꼭 바꿔야 되는데.....제발요ㅠㅠㅠ','배송/결제',NULL,'2025-04-08 18:14:08',3,'4444',NULL,NULL,NULL,'배송 일자 바꾸고 싶어요ㅠㅠ'),(5,NULL,'박춘식','50 저희집 따님이 동물성 생크림이 아니면 안 먹어서요. 어떤 생크림 사용하시는지...\r\n이런 질문하면 진상인가요...? 죄송합니다....','기타문의',NULL,'2025-04-08 18:28:00',2,'3333',NULL,NULL,NULL,'동물성 생크림인가요, 식물성 생크림인가요?'),(6,NULL,'초코생크림이좋아','초코맛 생크림이 초코맛이 너무 연해요;; 이런 것도 초코라고 하나요? 환불해주세요!!!!! 다 먹었긴 한데 기분이 나빠요. 억지로 먹었네요. 환불해주세요.','교환/환불',NULL,'2025-04-08 19:03:27',4,'2222',NULL,NULL,NULL,'초코맛이 안 진해서 환불하고 싶어요;;'),(7,NULL,'링바링','도안에서 수정하고 싶은 부분이 있어서요. 이걸로 바꾸고 싶어요..! 그래도 되나용?','도안문의','uploads/다운로드 (2).jpg','2025-04-08 19:05:10',7,'4444',NULL,NULL,NULL,'도안 바꾸고 싶어요!!');
/*!40000 ALTER TABLE `question` ENABLE KEYS */;
UNLOCK TABLES;

