INSERT INTO `review` VALUES (18,NULL,3,'링바링',1,'너무 맛이 없어요..... 이게 키위 맛인지 청사과 맛인지... 겉모습도 찰흙 같고','','2025-05-20 04:06:28',5,'1111','ORD20250520-9a2fab0a',7362),(19,NULL,58,'링바링',2,'아... 케이크가 너무 가격에 비해서 작네요.. 그 점이 가장 아쉽고 맛은 뭐.. 평범하네요','Hello Kitty memes - Keabetswe - Chaos kitty_15a41a60.jpeg','2025-05-20 04:18:11',1,'1111','ORD20250520-b8a360d2',7363),(20,NULL,25,'졸업하자',5,'커비가 귀엽고 케이크는 맛있어요~!! 또 여기서 구매할게요~~','커비_2ffb84a0.jpeg','2025-05-20 04:20:33',1,'2222','ORD20250520-822a7fcf',7364),(21,NULL,9,'졸업하자',5,'케이크가 너무 귀엽고 맛있었습니다. 레몬 맛으로 요청드렸는데, 친절하게 응대해 주셔서 감사했고 기분 좋은 경험이었어요!','kakao_4e8b92d7.png','2025-05-09 00:00:00',2,'2222','ORD1747137912055',7350),(22,NULL,57,'졸업하자',5,'결혼식 당일, 케이크를 처음 봤을 때 눈물이 날 뻔했어요.\r\n제가 요청한 디자인 그대로 너무 예쁘게 만들어 주셔서 정말 감동이었습니다.\r\n신랑, 하객, 가족들 모두 \"케이크 너무 예쁘다\", \"사진 찍고 싶다\"며 칭찬이 끊이질 않았어요.\r\n\r\n맛도 기대 이상이었어요! 보통 예쁜 케이크는 맛이 아쉽다는 말이 많은데, 이 케이크는 촉촉하고 부드러워서 다들 정말 맛있게 먹었답니다.\r\n무엇보다 주문부터 수령까지 친절하게 응대해 주셔서 준비 과정도 기분 좋았어요.','good_f0fee3ad.png','2025-05-20 04:23:17',2,'1234','ORD20250502-9b7ce74e',7339),(23,NULL,116,'박춘식',3,'귀여워요.. 제가 좋아하는 가나디 캐릭터를 케이크에 그려주시다니.. 감격했어요','ganadi_c19b6653.jpeg','2025-05-18 00:00:00',1,'1111','ORD20250520-e258c01d',NULL),(24,NULL,23,'박춘식',5,'보기 좋은 것이 먹기도 좋다더니, 정말 그 말이 딱 맞아요!\r\n케이크 디자인이 너무 예뻐서 한참을 바라보다가 아까워서 쉽게 자르지도 못했어요.\r\n하지만 한 입 먹는 순간, 비주얼만큼이나 맛도 훌륭해서 감탄이 절로 나왔답니다.\r\n정성 가득한 케이크 덕분에 소중한 날이 더 특별해졌어요. 정말 만족해요!','birthcake(3)_e53d52c8.jpg','2025-05-20 17:16:16',8,'1234','ORD1747683122161',NULL),(25,NULL,118,'박춘식',4,'맛이 좋아요~ 근데 디자인이 한정적이어서 밋밋하게 느껴지네요..','','2025-05-20 18:24:17',4,'1234','ORD20250520-e03211f6',NULL);
/*!40000 ALTER TABLE `review` ENABLE KEYS */;
